INSERT INTO "public"."session_content" ("id", "serial_no", "date_raw", "session_date", "title", "description", "category", "type", "linkedin_url", "image_url", "media_urls", "created_at") VALUES (1, 1, '8th Nov 2025', '2025-11-08', 'Alumni Success Story - Dhruvkumar Patel', ' Alumni Connect Session at LDRP-ITR, KSV! Mr. Dhruvkumar Patel shared valuable insights on research-driven career growth and technical excellence.', 'success', 'photo', 'https://www.linkedin.com/posts/mmpsrpc_ksv-ldrpitr-mmpsrpc-activity-7393559476517273600-F8s-', null, ARRAY['/Sessions/Alumni-Success-Dhruvkumar/img-1.jpg','/Sessions/Alumni-Success-Dhruvkumar/img-2.jpg','/Sessions/Alumni-Success-Dhruvkumar/img-3.jpg','/Sessions/Alumni-Success-Dhruvkumar/img-4.jpg','/Sessions/Alumni-Success-Dhruvkumar/img-5.jpg'], '2026-04-07 20:08:43.56695+00'), (2, 2, '12th Dec 2025', '2025-12-12', 'Students Research Lab Presents: Debate on Plots and Maps', 'The MMPSRPC Students Research Lab at KSV nurtures a progressive learning culture where students go beyond routine academics through weekly discussions and spontaneous exercises. This environment enhances analytical thinking, communication, and collaboration, helping students develop a strong research mindset and a more structured academic approach.', 'learning', 'video', 'https://www.linkedin.com/posts/mmpsrpc_mmpsrpc-ksv-studentsresearchlab-activity-7405172370459668481-6zQI', null, ARRAY['/Sessions/Learning-Cullture-of-MMPSRPC-SRL/video-6.mp4'], '2026-04-07 20:08:43.56695+00'), (3, 3, '27th Dec 2025', '2025-12-27', 'Alumni Success Story - Manan Darji (Google), Dhwani Jakhaniya (AMD)', 'Alumni of the CE Department, LDRP ITR, KSV conducted an insightful interaction session highlighting focused effort, mentorship, and adaptability for professional growth.', 'success', 'video', 'https://www.linkedin.com/posts/mmpsrpc_mmpsrpc-ksv-svkm-mmpsrc-activity-7413813644284682240-u9XF', null, ARRAY['/Sessions/Alumni-Success-Manan-Dhwani/video-1.mp4'], '2026-04-07 20:08:43.56695+00'), (4, 4, '3rd Jan 2026', '2026-01-03', 'Alumni Success Story - Shubham Kumar Chandravanshi (Deloitte), Dhruvkumar Patel (Myntra), Jay Patel (QloudX)', 'The Alumni Connect Session at the Student Research Lab, M. M. Patel Students Research Project Cell, KSV, brought together students and alumni for an insightful interaction focused on industry exposure, career journeys, and key professional learnings.', 'success', 'video', 'https://www.linkedin.com/posts/mmpsrpc_ksv-svkm-mmpsrpc-activity-7417800043421843456-rV2a', null, ARRAY['/Sessions/Alumni-Success-Shubham-Dhruvkumar-Jay/video-2.mp4'], '2026-04-07 20:08:43.56695+00'), (5, 5, '12th Feb 2026', '2026-02-12', 'Written and Verbal Articulation of Algorithmic Concepts', 'At the Students Research Lab under the M. M. Patel Students Research Project Cell, KSV (MMPSRPC), Kadi Sarva Vishwavidyalaya, Gandhinagar, an academic session focused on efficient analysis of recursive problems using structured and optimized approaches.', 'learning', 'video', 'https://www.linkedin.com/posts/mmpsrpc_mmpsrpc-ksv-svkm-activity-7412364021376413696-DFUn', null, ARRAY['/Sessions/Articulation-of-Algorithmic-Concepts/video-3.mp4'], '2026-04-07 20:08:43.56695+00'), (6, 6, '25th Feb 2026', '2026-02-25', 'Algorithm Optimization Through Recurrence Analysis', 'At the Students Research Lab under the M. M. Patel Students Research Project Cell, KSV (MMPSRPC), Kadi Sarva Vishwavidyalaya, Gandhinagar, students participated in an interactive session focused on algorithm optimization.', 'learning', 'video', 'https://www.linkedin.com/posts/mmpsrpc_mmpsrpc-ksv-svkm-activity-7411274469664759809-rDsK', null, ARRAY['/Sessions/Algorithm-Optimization/video-1.mp4'], '2026-04-07 20:08:43.56695+00');